import requests
from saml2.client import Saml2Client
from saml2.saml import SamlAssertion

def build_saml_request(destination_url, user_info):
    # Create SAML client
    saml_client = Saml2Client()

    # Set SAML request parameters
    saml_request = saml_client.create_authn_request(
        destination=destination_url,
        user=user_info['username'],
        password=user_info['password']
    )

    # Encode SAML request as XML
    saml_xml = saml_request.to_xml()

    # Send SAML request to Identity Provider
    response = requests.post(
        destination_url,
        data={'SAMLRequest': saml_xml}
    )

    # Return SAML response
    return response.text